// Extract message from Groq response
const groqResponse = $input.first().json;

let message = '';

if (groqResponse.choices && groqResponse.choices[0] && groqResponse.choices[0].message) {
  message = groqResponse.choices[0].message.content.trim();
} else {
  message = 'Mesaj oluşturulamadı. Lütfen tekrar deneyin.';
}

return {
  json: {
    message: message,
    success: true
  }
};

// Build personalized outreach prompt
const input = $input.first().json.body;

const leadName    = input.leadName    || 'Merhaba';
const company     = input.company     || 'işletmeniz';
const sector      = input.sector      || 'İşletme';
const rating      = input.rating;
const hasWebsite  = input.hasWebsite;
const hasEmail    = input.hasEmail;
const tone        = input.tone        || 'professional';
const businessName   = input.businessName   || '';
const businessOffer  = input.businessOffer  || '';

// Sektöre göre içgörü ipuçları
const sectorInsights = {
  'Kafe':             'Kafe işletmelerinin %78\'i yeni müşterilerini Google Haritalar üzerinden buluyor.',
  'Restoran':         'Restoran rezervasyonlarının %65\'i artık mobil üzerinden geliyor.',
  'Diş':              'Diş kliniklerinde online randevu sistemi olan yerler %3 daha fazla hasta görüyor.',
  'Kuaför':           'Kuaför salonlarında Instagram takipçisi olan yerler doluluk oranını %40 artırıyor.',
  'Güzellik':         'Güzellik merkezlerinde Google yorumları randevu kararlarını %90 etkiliyor.',
  'Veteriner':        'Veteriner klinikleri için online görünürlük yeni hasta kazanımını 2.5x artırıyor.',
  'Spor':             'Spor tesislerinde dijital üyelik sistemi churn oranını %35 düşürüyor.',
  'Eğitim':           'Eğitim kurumlarında WhatsApp ile iletişim kayıt dönüşümünü %60 artırıyor.',
};

// Rating bazlı kişiselleştirme
let ratingInsight = '';
if (rating >= 4.5) {
  ratingInsight = `Google'da ${rating} puanla sektörün en iyileri arasındasınız`;
} else if (rating >= 4.0) {
  ratingInsight = `${rating} puanlık Google skorunuzu 4.8'in üzerine çıkarmak`;
} else if (rating > 0) {
  ratingInsight = `Google puanınızı rakiplerinizin önüne geçirecek bir strateji`;
} else {
  ratingInsight = `${company} için özel hazırladığımız büyüme analizi`;
}

// Website durumu
const websiteNote = hasWebsite
  ? 'Web sitenizi inceledim ve potansiyelini gördüm.'
  : 'Web sitesi olmayan işletmelerin kaçırdığı fırsatları somut rakamlarla görebilirsiniz.';

// Ton ayarları
const toneGuide = {
  professional: 'Güven veren, ölçülü profesyonel bir ton kullan. Rakam ve somut veri kullan.',
  friendly:     'Sıcak, samimi ama saygılı bir ton kullan. Sanki tanıdık biri gibi yaz.',
  curious:      'Merak uyandır ama cevabı verme. Karşı tarafın "nasıl?" diye sormasını sağla.',
};

const sectorHint = sectorInsights[sector] || `${sector} sektöründe öne çıkan işletmelerin ortak bir sırrı var.`;

const systemPrompt = `Sen Türkiye'deki yerel işletmelere yönelik WhatsApp outreach konusunda uzman bir satış copywriter'sın. 
Yazdığın mesajlar taciz gibi değil, gerçekten yardım etmek isteyen biri gibi hissettirmeli.`;

const userPrompt = `Aşağıdaki işletme için WhatsApp'ta ilk temas mesajı yaz:

İşletme: ${company}
Yetkili: ${leadName}
Sektör: ${sector}
${rating ? `Google Puanı: ${rating}/5` : ''}
${hasWebsite !== undefined ? `Web Sitesi: ${hasWebsite ? 'Var' : 'Yok'}` : ''}
${businessName ? `Gönderen: ${businessName}` : ''}
${businessOffer ? `Sunulan hizmet: ${businessOffer}` : ''}

MESAJ YAPISI (3 element, bu sırayla):
1. SELAMLAma + KİŞİSELLEŞTİRME: İsimle selamla, işletmelerine özel bir gözlem yap (rating veya sektör gerçeğini kullan: "${ratingInsight}")
2. MERAK ARALIĞI: Sektör içgörüsüyle merak uyandır, ama çözümü açıklama → "${sectorHint}"
3. TEK SORU: Satışa değil, bir sonraki küçük adıma yönlendiren yumuşak bir soru

TON: ${toneGuide[tone] || toneGuide.professional}

KURALLAR:
- Maksimum 3 cümle, 70-90 kelime
- "Teklif", "satış", "pazarlama", "reklam" kelimelerini KULLANMA
- Emoji: sadece 1-2 tane, doğal yerlerde
- Kalıp cümleler kullanma, bu mesaj sadece ${company}'e yazılmış gibi hissettirmeli
- Türkçe, sade ve akıcı yaz
- Mesaj spam gibi görünmemeli — meraklı biri gibi hissettirmeli`;

return {
  json: {
    systemPrompt,
    userPrompt
  }
};
